function calculateQuoteAmount(
    uint256 componentQuantity,  // in component token decimals
    uint256 componentPrice      // assumed 18 decimals, but may not be
) internal pure returns (uint256) {
    // preciseMul expects price in WAD (1e18), but if component is 18dp
    // and quote is 6dp, price must be in 6dp for math to work
    return componentQuantity.preciseMul(componentPrice);
}

function getExponentialPrice(uint256 timeCoefficient, uint256 timeBucket) internal returns (uint256) {
    int256 expArgument = int256(timeCoefficient * timeBucket);
    // When expArgument is small (e.g., 1e6 instead of 1e18),
    // expWad returns near-linear values instead of exponential
    uint256 expExpression = uint256(FixedPointMathLib.expWad(expArgument));
    uint256 priceChange = scalingFactor * expExpression - WAD;
    return priceChange;
}

function buyQuote(uint256 outputAmount) public view returns (uint256) {
    // When reserves are large relative to outputAmount and token has low decimals,
    // integer division can round down to zero
    return (outputAmount * baseTokenReserves) / (fractionalTokenReserves - outputAmount);
}

